HB_Manual_Fail := NOT HB_Manual_OK; 
HB_Remote_Fail := NOT HB_Remote_OK; 

IF HB_Manual_Fail AND HB_Remote_Fail THEN 
	EmergencyShutdown := TRUE; 
END_IF


IF EmergencyShutdown THEN 
	RETURN;
END_IF

CR710S_Config(); 			//IO Configuration

IOWrapper.READ_INPUTS(); 	//Call IOWrapper Main Program and Read Data from Inputs   

fbInputProcessing(
	xReqManual 			:= IN0100.VAR_OUT.xValueDigital,
	xAckManual 			:= IN0101.VAR_OUT.xValueDigital, 
	xRelManual 			:= IN0102.VAR_OUT.xValueDigital, 
	xHB_Manual			:= IN0103.VAR_OUT.xValueDigital 
);

fbHB_Manual(xSignal := GVL_HeartBeat.HB_Manual_Signal); 
fbHB_Remote(xSignal := GVL_HeartBeat.HB_Remote_Signal); 

//Heartbeat generator
fbHBGen_Manual(); 
fbHBGen_Remote(); 

fbControlUnit(
    ReqManual  		:= GVL_IO.ReqManual,
	AckManual   	:= GVL_IO.AckManual,
	RelManual   	:= GVL_IO.RelManual,
    ReqRemote   	:= GVL_IO.ReqRemote,
    AckRemote   	:= GVL_IO.AckRemote,
    RelRemote   	:= GVL_IO.RelRemote,
	HB_Manual_OK 	:= GVL_HeartBeat.HB_Manual_OK,
	HB_Remote_OK 	:= GVL_HeartBeat.HB_Remote_OK
);

fbIntegrityCheck(
    ReqManual        := GVL_IO.ReqManual,
    ReqRemote        := GVL_IO.ReqRemote,
    AckManual        := GVL_IO.AckManual,
    AckRemote        := GVL_IO.AckRemote,
    RelManual        := GVL_IO.RelManual,
    RelRemote        := GVL_IO.RelRemote,
    HB_Manual_Signal := GVL_HeartBeat.HB_Manual_Signal,
    HB_Remote_Signal := GVL_HeartBeat.HB_Remote_Signal
);

fbOutputProcessing(
    ReqManual       := GVL_IO.ReqManual,
    ReqRemote       := GVL_IO.ReqRemote,
    GrantedManual   := fbControlUnit.GrantedManual,
    GrantedRemote   := fbControlUnit.GrantedRemote,
	Released 		:= fbControlUnit.Released,
	PendingReady 	:= fbControlUnit.PendingReady,
    Active          := fbControlUnit.Active,
    State           := fbControlUnit.State,
    HB_Manual_OK    := GVL_HeartBeat.HB_Manual_OK,
    HB_Remote_OK    := GVL_HeartBeat.HB_Remote_OK
);

fbDecisionLogger( 
	Active := fbControlUnit.Active,
	Pending := fbControlUnit.Pending,   
	State := fbControlUnit.State
); 

OUT0000.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_GrantedManual, 0, 2500);
