xPulse := (xSignal <> xPrevSignal);
xPrevSignal := xSignal;
// Om ingen ny puls kommer, låt timern gå 
tonTimeout(IN := NOT xPulse, PT := T#500MS);
xOk := NOT tonTimeout.Q;

//Initial state set
IF Active = EControlMode.INIT THEN 
	Active := EControlMode.MANUAL;
END_IF

//If in FailSafe then we block everything else
IF Active = EControlMode.FAILSAFE THEN 
	Pending := EPendingMode.NONE; //set pending to none
	State := ETransitionState.STABLE; //no transition active
	RETURN; 
END_IF

IF Active = EControlMode.REMOTE AND NOT HB_Remote_OK THEN
	Active := SEL(HB_Manual_OK, EControlMode.FAILSAFE, EControlMode.MANUAL); 
	Pending := EPendingMode.NONE; 
	State := ETransitionState.STABLE; 
	RETURN; 
END_IF 

IF Active = EControlMode.MANUAL AND NOT HB_Manual_OK THEN
	Active := SEL(HB_Remote_OK, EControlMode.FAILSAFE, EControlMode.REMOTE); 
	Pending := EPendingMode.NONE; 
	State := ETransitionState.STABLE; 
	RETURN;
END_IF

CASE State OF 
	//Stable: No transition is currently in progress
	ETransitionState.STABLE: 
	Pending := EPendingMode.NONE; //No one is trying to take over

		//Manual station requests control
		IF ReqManual AND NOT ReqRemote AND Active <> EControlMode.MANUAL AND
			HB_Manual_OK THEN 
				Pending := EPendingMode.PENDING_MANUAL; 
				State := ETransitionState.PENDING_ACK; 
		//Remote station requests control
		ELSIF ReqRemote AND NOT ReqManual AND Active <> EControlMode.REMOTE AND 
			HB_Remote_OK THEN
				Pending := EPendingMode.PENDING_REMOTE; 
				State := ETransitionState.PENDING_ACK; 
		END_IF

		IF Velocity > MaxVelocity OR SteeringAngle > MaxSteering THEN 
			//not allowed
		ELSIF ReqManual AND NOT ReqRemote AND Active <> EControlMode.MANUAL AND HB_Manual_OK THEN 
			Pending := EPendingMode.PENDING_MANUAL; 
			State := ETransitionState.PENDING_ACK; 
		ELSIF ReqRemote AND NOT ReqManual AND Active <> EControlMode.REMOTE AND HB_Remote_OK THEN 
			Pending := EPendingMode.PENDING_REMOTE; 
			State := ETransitionState.PENDING_ACK; 
		END_IF

	//Transition has been granted, waiting for acknowledgement from both control modes
	ETransitionState.PENDING_ACK:
		IF (GrantedManual AND (NOT ReqManual OR NOT HB_Manual_OK)) OR
		   (GrantedRemote AND (NOT ReqRemote OR NOT HB_Remote_OK)) THEN
			Pending := EPendingMode.NONE;
			State := ETransitionState.STABLE;
		ELSE
			Released := (Active = EControlMode.MANUAL AND RelManual) OR
					   (Active = EControlMode.REMOTE AND RelRemote);

			PendingReady := (Pending = EPendingMode.PENDING_MANUAL AND AckManual) OR
						   (Pending = EPendingMode.PENDING_REMOTE AND AckRemote);

			IF Released AND PendingReady THEN
				// Convert EPendingMode to EControlMode
				IF Pending = EPendingMode.PENDING_MANUAL THEN
					Active := EControlMode.MANUAL;
				ELSIF Pending = EPendingMode.PENDING_REMOTE THEN
					Pending := EPendingMode.NONE;
					State := ETransitionState.STABLE;
					Released := FALSE;
					ReqRemote := FALSE;
					ReqManual := FALSE;
				END_IF
			END_IF
		END_IF

		tAckTimer (IN := TRUE, PT := MaxAckTime); 

		IF tAckTimer.Q THEN 
			Pending := EPendingMode.NONE; 
			State := ETransitionState.STABLE; 
			tAckTimer (IN := FALSE); // Reset timer 
		END_IF

		//cancel if requesting station is dropped or lost its heartbeat
		IF (GrantedManual AND (NOT ReqManual OR NOT HB_Manual_OK)) OR 
			(GrantedRemote AND (NOT ReqRemote OR NOT HB_Remote_OK)) THEN
			Pending := EPendingMode.NONE; 
			State := ETransitionState.STABLE; 
			tAckTimer (IN := FALSE); // Reset timer
		ELSE 
			Released := (Active = EControlMode.MANUAL AND RelManual) OR 
			(Active = EControlMode.REMOTE AND RelRemote); 

			PendingReady := (Pending = EPendingMode.PENDING_MANUAL AND AckManual) OR 
			(Pending = EPendingMode.PENDING_REMOTE AND AckRemote); 

			IF Released AND PendingReady THEN 
				IF Pending = EPendingMode.PENDING_MANUAL THEN 
					Active := EControlMode.MANUAL; 
				ELSIF PEnding = EPendingMode.PENDING_REMOTE THEN 
					Active := EControlMode.REMOTE; 
				END_IF
				Pending := EPendingMode.NONE; 
				State := ETransitionState.STABLE; 
				tAckTimer(IN := FALSE); 
				Released := FALSE; 
				ReqRemote := FALSE; 
				ReqManual := FALSE; 
			END_IF
		END_IF

END_CASE


//Updated grant signals based on the current pending mode 
GrantedManual := (Pending = EPendingMode.PENDING_MANUAL);
GrantedRemote := (Pending = EPendingMode.PENDING_REMOTE);

GVL_IO.ReqManual := xReqManual; 
GVL_IO.AckManual := xAckManual; 
GVL_IO.RelManual := xRelManual; 

GVL_IO.ReqRemote := xReqRemote; 
GVL_IO.Ackremote := xAckRemote; 
GVL_IO.RelRemote := xRelRemote; 

GVL_HeartBeat.HB_Manual_Signal := xHB_Manual; 
GVL_HeartBeat.HB_Remote_Signal := xHB_Remote;

// Lamp outputs reflecting current system state
OUT_GrantedManual := GrantedManual; 
OUT_GrantedRemote := GrantedRemote; 
OUT_ActiveManual  := (Active = EControlMode.MANUAL); 
OUT_ActiveRemote  := (Active = EControlMode.REMOTE);
OUT_Pending		  := (State = ETransitionState.PENDING_ACK); 
OUT_PendingReady  := PendingReady; 
OUT_Released	  := Released; 
OUT_NoHB_Manual   := NOT HB_Manual_OK; 
OUT_NoHB_Remote   := NOT HB_Remote_OK; 
OUT_FailSafe	  :=(Active = EControlMode.FAILSAFE);

