Lamp_FailSafe               := (Active = EControlMode.FAILSAFE);
*)

//Start timer
tonToggle(IN := xEnable, PT := T#200MS);

//När timer gått, växla signal
IF tonToggle.Q THEN
	xSignal := NOT xSignal;
	xEnable := FALSE;
ELSE
	xEnable := TRUE;
END_IF;

IF (ReqManual AND ReqRemote) OR //two stations want control
   (ReqManual AND RelManual) OR //a station requesting and releasing at the same time
   (ReqRemote AND RelRemote) THEN
   	Valid        := FALSE; 
    ReqManual_Out := FALSE;
    ReqRemote_Out := FALSE;
    AckManual_Out := FALSE;
    AckRemote_Out := FALSE;
    RelManual_Out := FALSE;
    RelRemote_Out := FALSE;
    HB_Manual_Out := HB_Manual_Signal;
	HB_Remote_Out := HB_Remote_Signal;
    RETURN;
END_IF

Valid         := TRUE;
ReqManual_Out := ReqManual;
ReqRemote_Out := ReqRemote;
AckManual_Out := AckManual;
AckRemote_Out := AckRemote;
RelManual_Out := RelManual;
RelRemote_Out := RelRemote;
HB_Manual_Out := HB_Manual_Signal;
HB_Remote_Out := HB_Remote_Signal;

IF Active <> LastActive OR Pending <> LastPending OR State <> LastState THEN 
	GVL_State.Active := Active; 
	GVL_State.Pending := Pending; 
	GVL_State.State := State;

	LastActive := Active; 
 	LastPending := Pending; 
	LastState := State; 
END_IF
